import { Link } from "react-router-dom";

export default function ItemCard({ item }) {
  return (
    <Link
      to={`/detail/${item._id}`}
      style={{
        textDecoration: "none",
        color: "inherit"
      }}
    >
      <div
        style={{
          background: "white",
          borderRadius: "16px",
          overflow: "hidden",
          boxShadow: "0 4px 12px rgba(0,0,0,0.1)"
        }}
      >
        <img
          src={`http://localhost:5000/uploads/${item.image}`}
          alt={item.name}
          style={{
            width: "100%",
            height: "250px",
            objectFit: "fill"
          }}
        />

        <div style={{ padding: "15px" }}>
          <h3>{item.name}</h3>
          <p>Rp {item.price}</p>
        </div>
      </div>
    </Link>
  );
}
